class Solution:
    def isScramble(self, s1: str, s2: str) -> bool:
        from functools import lru_cache
        n = len(s1)
        if sorted(s1) != sorted(s2): return False
        @lru_cache(None)
        def dfs(i, j, l):
            if l == 1: return s1[i] == s2[j]
            for k in range(1, l):
                if (dfs(i, j, k) and dfs(i+k, j+k, l-k)) or \
                   (dfs(i, j+k, l-k) and dfs(i+k, j, k)):
                    return True
            return False
        return dfs(0, 0, n)

